}

func (bm *BitMap) FromBytes(data []byte) error {
	if len(data) != config.BytesPerBitmap {
		return errors.NewError(errors.ErrCodeFileOperation, 
			fmt.Sprintf("bitmap requires %d bytes, got %d", config.BytesPerBitmap, len(data)))
