package config

const (
	BitsPerPage      = 128             // 128 элементов на страницу
	BytesPerBitmap   = BitsPerPage / 8 // bitmap в байтах
	PhysicalPageSize = 512             // 512 байт - физ размер страницы по ТЗ
)

// PageDataSize размер данных страницы для типа
func PageDataSize(elemSize int) int {
	return BitsPerPage * elemSize
}

func TotalPageSize(elemSize int) int {
	dataSize := PageDataSize(elemSize)
	total := BytesPerBitmap + dataSize
	return ((total + PhysicalPageSize - 1) / PhysicalPageSize) * PhysicalPageSize // Выравниваем до PhysicalPageSize
}

// Package config provides configuration constants for Virtual Memory Management system.
package config

const (
	// Page configuration
	BitsPerPage      = 128             // 128 elements per page
	BytesPerBitmap   = BitsPerPage / 8 // bitmap size in bytes
	PhysicalPageSize = 512             // 512 bytes - physical page size

	// Cache configuration
	// MinCacheSize is the minimum number of pages to keep in memory
	MinCacheSize = 3
	// MaxCacheSize is the maximum number of pages that can be cached
	MaxCacheSize = 100
	// DefaultCacheSize is the default cache capacity if not specified
	DefaultCacheSize = 10
)

// PageDataSize размер данных страницы для типа
func PageDataSize(elemSize int) int {
	return BitsPerPage * elemSize
}

func TotalPageSize(elemSize int) int {
	dataSize := PageDataSize(elemSize)
	total := BytesPerBitmap + dataSize
	return ((total + PhysicalPageSize - 1) / PhysicalPageSize) * PhysicalPageSize // Выравниваем до PhysicalPageSize
}

package errors

import (
	"errors"
	"fmt"
)

type VMMError struct {
	Code    int
	Message string
	Err     error // Underlying error for error wrapping
}

func (e *VMMError) Error() string {
	if e.Err != nil {
		return fmt.Sprintf("%s: %v", e.Message, e.Err)
	}
	return e.Message
}

// Unwrap returns the underlying error, enabling errors.Is and errors.As
func (e *VMMError) Unwrap() error {
	return e.Err
}

const (
	ErrCodeFileNotFound     = -1
	ErrCodeOutOfMemory      = -2
	ErrCodeIndexOutOfRange  = -3
	ErrCodeFileOperation    = -4
	ErrCodeInvalidType      = -5
	ErrCodeInsufficientDisk = -6
	ErrCodeInvalidHandle    = -7
	ErrCodePageNotFound     = -8
)

var (
	ErrFileNotFound     = &VMMError{Code: ErrCodeFileNotFound, Message: "File not found"}
	ErrOutOfMemory      = &VMMError{Code: ErrCodeOutOfMemory, Message: "Out of memory"}
	ErrIndexOutOfRange  = &VMMError{Code: ErrCodeIndexOutOfRange, Message: "Index out of range"}
	ErrFileOperation    = &VMMError{Code: ErrCodeFileOperation, Message: "File operation failed"}
	ErrInvalidType      = &VMMError{Code: ErrCodeInvalidType, Message: "Invalid array type"}
	ErrInsufficientDisk = &VMMError{Code: ErrCodeInsufficientDisk, Message: "Insufficient disk space"}
	ErrInvalidHandle    = &VMMError{Code: ErrCodeInvalidHandle, Message: "Invalid handle"}
	ErrPageNotFound     = &VMMError{Code: ErrCodePageNotFound, Message: "Page not found"}
)

// NewError creates a custom error
func NewError(code int, message string) *VMMError {
	return &VMMError{Code: code, Message: message}
}

// NewErrorWithWrapped creates a VMMError with an underlying wrapped error
func NewErrorWithWrapped(code int, message string, err error) *VMMError {
	return &VMMError{Code: code, Message: message, Err: err}
}

// GetErrorCode returns the error code from a VMMError, or -999 if not a VMMError
func GetErrorCode(err error) int {
	if err == nil {
		return 0
	}
	// Try to unwrap to find VMMError
	var vmmErr *VMMError
	if errors.As(err, &vmmErr) {
		return vmmErr.Code
	}
	return -999
}

