// Package storage provides interfaces and implementations for persistent storage operations.
package storage

import "VirtualMemoryManagement/types/page"

// PageStorage defines the interface for reading and writing pages to disk.
// This allows for different storage implementations (file, database, etc.)
type PageStorage interface {
	// ReadPage reads a page from storage at the specified page number.
	ReadPage(pageNumber int) (*page.Page, error)

	// WritePage writes a page to storage.
	WritePage(p *page.Page) error

	// Close closes the storage and releases any resources.
	Close() error

	// ArrayInfo returns information about the array structure.
	ArrayInfo() interface{}
}

// VarcharStorage defines the interface for reading and writing variable-length strings.
type VarcharStorage interface {
	// WriteString writes a string at the specified offset and returns the new offset.
	WriteString(offset int64, s string) error

	// ReadString reads a string from the specified offset.
	ReadString(offset int64) (string, error)

	// GetCurrentOffset returns the current write position in the file.
	GetCurrentOffset() (int64, error)

	// Close closes the storage and releases any resources.
	Close() error
}

// Package storage provides interfaces and implementations for persistent storage operations.
package storage

import "VirtualMemoryManagement/types/page"

// PageStorage defines the interface for reading and writing pages to disk.
type PageStorage interface {
	ReadPage(pageNumber int) (*page.Page, error)
	WritePage(p *page.Page) error
	Close() error
	ArrayInfo() interface{}
}

// VarcharStorage defines the interface for reading and writing variable-length strings.
type VarcharStorage interface {
	WriteString(offset int64, s string) error
	ReadString(offset int64) (string, error)
	GetCurrentOffset() (int64, error)
	Close() error
}

package cache

import "VirtualMemoryManagement/types/page"

type lruNode struct {
	page *page.Page
	prev *lruNode
	next *lruNode
}

type LRUCache struct {
	capacity int
	head     *lruNode
	tail     *lruNode
	pageMap  map[int]*lruNode
}

func NewLRU(capacity int) *LRUCache {
	lru := &LRUCache{
		capacity: capacity,
		pageMap:  make(map[int]*lruNode),
	}

	lru.head = &lruNode{}
	lru.tail = &lruNode{}
	lru.head.next = lru.tail
	lru.tail.prev = lru.head

	return lru
}

func (lru *LRUCache) Get(pageNumber int) *page.Page {
	if node, exists := lru.pageMap[pageNumber]; exists {
		lru.moveToFront(node)
		return node.page
	}
	return nil
}

func (lru *LRUCache) Put(p *page.Page) *page.Page {
	pageNumber := p.AbsoluteNumber

	if node, exists := lru.pageMap[pageNumber]; exists {
		node.page = p
		lru.moveToFront(node)
		return nil
	}

	var evicted *page.Page
	if len(lru.pageMap) >= lru.capacity {
		evicted = lru.evictLRU()
	}

	newNode := &lruNode{page: p}
	lru.pageMap[pageNumber] = newNode
	lru.addToFront(newNode)

	return evicted
}

func (lru *LRUCache) Contains(pageNumber int) bool {
	_, exists := lru.pageMap[pageNumber]
	return exists
}

func (lru *LRUCache) Size() int {
	return len(lru.pageMap)
}

func (lru *LRUCache) All() []*page.Page {
	var result []*page.Page
	for _, node := range lru.pageMap {
		result = append(result, node.page)
	}
	return result
}

func (lru *LRUCache) moveToFront(node *lruNode) {
	lru.removeNode(node)
	lru.addToFront(node)
}

func (lru *LRUCache) addToFront(node *lruNode) {
	node.prev = lru.head
	node.next = lru.head.next
	lru.head.next.prev = node
	lru.head.next = node
}

func (lru *LRUCache) removeNode(node *lruNode) {
	node.prev.next = node.next
	node.next.prev = node.prev
}

func (lru *LRUCache) evictLRU() *page.Page {
	if lru.tail.prev == lru.head {
		return nil
	}

	node := lru.tail.prev
	lru.removeNode(node)
	delete(lru.pageMap, node.page.AbsoluteNumber)
	return node.page
}

package cache

import "VirtualMemoryManagement/types/page"

type lruNode struct {
	page *page.Page
	prev *lruNode
	next *lruNode
}

// LRUCache implements the Cache interface using a Least Recently Used eviction policy.
// It maintains a doubly-linked list to track access order and a map for O(1) lookups.
type LRUCache struct {
	capacity int
	head     *lruNode
	tail     *lruNode
	pageMap  map[int]*lruNode
}

// Verify that LRUCache implements Cache interface
var _ Cache = (*LRUCache)(nil)

func NewLRU(capacity int) *LRUCache {
	lru := &LRUCache{
		capacity: capacity,
		pageMap:  make(map[int]*lruNode),
	}

	lru.head = &lruNode{}
	lru.tail = &lruNode{}
	lru.head.next = lru.tail
	lru.tail.prev = lru.head

	return lru
}

func (lru *LRUCache) Get(pageNumber int) *page.Page {
	if node, exists := lru.pageMap[pageNumber]; exists {
		lru.moveToFront(node)
		return node.page
	}
	return nil
}

func (lru *LRUCache) Put(p *page.Page) *page.Page {
	pageNumber := p.AbsoluteNumber

	if node, exists := lru.pageMap[pageNumber]; exists {
		node.page = p
		lru.moveToFront(node)
		return nil
	}

	var evicted *page.Page
	if len(lru.pageMap) >= lru.capacity {
		evicted = lru.evictLRU()
	}

	newNode := &lruNode{page: p}
	lru.pageMap[pageNumber] = newNode
	lru.addToFront(newNode)

	return evicted
}

func (lru *LRUCache) Contains(pageNumber int) bool {
	_, exists := lru.pageMap[pageNumber]
	return exists
}

func (lru *LRUCache) Size() int {
	return len(lru.pageMap)
}

func (lru *LRUCache) All() []*page.Page {
	var result []*page.Page
	for _, node := range lru.pageMap {
		result = append(result, node.page)
	}
	return result
}

func (lru *LRUCache) moveToFront(node *lruNode) {
	lru.removeNode(node)
	lru.addToFront(node)
}

func (lru *LRUCache) addToFront(node *lruNode) {
	node.prev = lru.head
	node.next = lru.head.next
	lru.head.next.prev = node
	lru.head.next = node
}

func (lru *LRUCache) removeNode(node *lruNode) {
	node.prev.next = node.next
	node.next.prev = node.prev
}

func (lru *LRUCache) evictLRU() *page.Page {
	if lru.tail.prev == lru.head {
		return nil
	}

	node := lru.tail.prev
	lru.removeNode(node)
	delete(lru.pageMap, node.page.AbsoluteNumber)
	return node.page
}

package storage

import (
	"VirtualMemoryManagement/config"
	"VirtualMemoryManagement/errors"
	"VirtualMemoryManagement/types/array"
	"VirtualMemoryManagement/types/page"
	"io"
	"os"
)

const (
	SignatureSize = 2
	Signature     = "ВМ"
)

type PageFile struct {
	file      *os.File
	filename  string
	arrayInfo *array.Info
	binaryIO  *BinaryIO
}

func NewPageFile(filename string) *PageFile {
	return &PageFile{
		filename: filename,
		binaryIO: NewBinaryIO(),
	}
}

func (pf *PageFile) Create(size int, typ array.Type, stringLength int) error {
	f, err := os.OpenFile(pf.filename, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0644)
	if err != nil {
		return errors.ErrFileOperation
	}
	pf.file = f

	pf.arrayInfo = array.NewInfo(size, typ, stringLength)

	if _, err := f.WriteString(Signature); err != nil {
		return errors.ErrFileOperation
	}

	header := &Header{
		Size:         int64(size),
		Type:         typ,
		StringLength: int32(stringLength),
	}
	if err := header.WriteTo(f); err != nil {
		return errors.ErrFileOperation
	}

	for i := 0; i < pf.arrayInfo.PageCount; i++ {
		pageSize := config.TotalPageSize(pf.arrayInfo.ElementSize)
		zeroPage := make([]byte, pageSize)
		if _, err := f.Write(zeroPage); err != nil {
			return errors.ErrInsufficientDisk
		}
	}

	return nil
}

func (pf *PageFile) Open(filename string) error {
	f, err := os.OpenFile(filename, os.O_RDWR, 0644)
	if err != nil {
		return errors.ErrFileNotFound
	}
	pf.file = f
	pf.filename = filename

	sig := make([]byte, SignatureSize)
	if _, err := f.Read(sig); err != nil {
		return errors.ErrFileOperation
	}

	if string(sig) != Signature {
		return errors.ErrInvalidType
	}

	header := &Header{}
	if err := header.ReadFrom(f); err != nil {
		return errors.ErrFileOperation
	}

	pf.arrayInfo = array.NewInfo(int(header.Size), header.Type, int(header.StringLength))

	return nil
}

func (pf *PageFile) Close() error {
	if pf.file != nil {
		return pf.file.Close()
	}
	return nil
}

func (pf *PageFile) ReadPage(pageNumber int) (*page.Page, error) {
	if pageNumber < 0 || pageNumber >= pf.arrayInfo.PageCount {
		return nil, errors.ErrIndexOutOfRange
	}

	offset := pf.calculatePageOffset(pageNumber)
	if _, err := pf.file.Seek(offset, io.SeekStart); err != nil {
		return nil, errors.ErrFileOperation
	}

	bitmapData := make([]byte, config.BytesPerBitmap)
	if _, err := io.ReadFull(pf.file, bitmapData); err != nil {
		return nil, errors.ErrFileOperation
	}

	pageData := make([]byte, config.PageDataSize(pf.arrayInfo.ElementSize))
	if _, err := io.ReadFull(pf.file, pageData); err != nil {
		return nil, errors.ErrFileOperation
	}

	p, err := page.NewWithData(pageNumber, pf.arrayInfo.ElementSize, bitmapData, pageData)
	if err != nil {
		return nil, err
	}

	return p, nil
}

func (pf *PageFile) WritePage(p *page.Page) error {
	if p.AbsoluteNumber < 0 || p.AbsoluteNumber >= pf.arrayInfo.PageCount {
		return errors.ErrIndexOutOfRange
	}

	offset := pf.calculatePageOffset(p.AbsoluteNumber)
	if _, err := pf.file.Seek(offset, io.SeekStart); err != nil {
		return errors.ErrFileOperation
	}

	if _, err := pf.file.Write(p.Bitmap().Bytes()); err != nil {
		return errors.ErrFileOperation
	}

	if _, err := pf.file.Write(p.Data()); err != nil {
		return errors.ErrFileOperation
	}

	return nil
}

func (pf *PageFile) ArrayInfo() *array.Info {
	return pf.arrayInfo
}

func (pf *PageFile) calculatePageOffset(pageNumber int) int64 {
	headerSize := int64(SignatureSize) + int64((&Header{}).Size_())
	pageSize := int64(config.TotalPageSize(pf.arrayInfo.ElementSize))
	return headerSize + int64(pageNumber)*pageSize
}

package storage

import (
	"VirtualMemoryManagement/config"
	"VirtualMemoryManagement/errors"
	"VirtualMemoryManagement/types/array"
	"VirtualMemoryManagement/types/page"
	"io"
	"os"
)

const (
	SignatureSize = 2
	Signature     = "ВМ"
)

// PageFile implements the PageStorage interface for file-based page persistence.
// It handles reading and writing pages to disk with proper serialization.
type PageFile struct {
	file      *os.File
	filename  string
	arrayInfo *array.Info
	binaryIO  *BinaryIO
}

// Verify that PageFile implements PageStorage interface
var _ PageStorage = (*PageFile)(nil)

func NewPageFile(filename string) *PageFile {
	return &PageFile{
		filename: filename,
		binaryIO: NewBinaryIO(),
	}
}

func (pf *PageFile) Create(size int, typ array.Type, stringLength int) error {
	f, err := os.OpenFile(pf.filename, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0644)
	if err != nil {
		return errors.ErrFileOperation
	}
	pf.file = f

	pf.arrayInfo = array.NewInfo(size, typ, stringLength)

	if _, err := f.WriteString(Signature); err != nil {
		return errors.ErrFileOperation
	}

	header := &Header{
		Size:         int64(size),
		Type:         typ,
		StringLength: int32(stringLength),
	}
	if err := header.WriteTo(f); err != nil {
		return errors.ErrFileOperation
	}

	for i := 0; i < pf.arrayInfo.PageCount; i++ {
		pageSize := config.TotalPageSize(pf.arrayInfo.ElementSize)
		zeroPage := make([]byte, pageSize)
		if _, err := f.Write(zeroPage); err != nil {
			return errors.ErrInsufficientDisk
		}
	}

	return nil
}

func (pf *PageFile) Open(filename string) error {
	f, err := os.OpenFile(filename, os.O_RDWR, 0644)
	if err != nil {
		return errors.ErrFileNotFound
	}
	pf.file = f
	pf.filename = filename

	sig := make([]byte, SignatureSize)
	if _, err := f.Read(sig); err != nil {
		return errors.ErrFileOperation
	}

	if string(sig) != Signature {
		return errors.ErrInvalidType
	}

	header := &Header{}
	if err := header.ReadFrom(f); err != nil {
		return errors.ErrFileOperation
	}

	pf.arrayInfo = array.NewInfo(int(header.Size), header.Type, int(header.StringLength))

	return nil
}

func (pf *PageFile) Close() error {
	if pf.file != nil {
		return pf.file.Close()
	}
	return nil
}

func (pf *PageFile) ReadPage(pageNumber int) (*page.Page, error) {
	if pageNumber < 0 || pageNumber >= pf.arrayInfo.PageCount {
		return nil, errors.ErrIndexOutOfRange
	}

	offset := pf.calculatePageOffset(pageNumber)
	if _, err := pf.file.Seek(offset, io.SeekStart); err != nil {
		return nil, errors.ErrFileOperation
	}

	bitmapData := make([]byte, config.BytesPerBitmap)
	if _, err := io.ReadFull(pf.file, bitmapData); err != nil {
		return nil, errors.ErrFileOperation
	}

	pageData := make([]byte, config.PageDataSize(pf.arrayInfo.ElementSize))
	if _, err := io.ReadFull(pf.file, pageData); err != nil {
		return nil, errors.ErrFileOperation
	}

	p, err := page.NewWithData(pageNumber, pf.arrayInfo.ElementSize, bitmapData, pageData)
	if err != nil {
		return nil, err
	}

	return p, nil
}

func (pf *PageFile) WritePage(p *page.Page) error {
	if p.AbsoluteNumber < 0 || p.AbsoluteNumber >= pf.arrayInfo.PageCount {
		return errors.ErrIndexOutOfRange
	}

	offset := pf.calculatePageOffset(p.AbsoluteNumber)
	if _, err := pf.file.Seek(offset, io.SeekStart); err != nil {
		return errors.ErrFileOperation
	}

	if _, err := pf.file.Write(p.Bitmap().Bytes()); err != nil {
		return errors.ErrFileOperation
	}

	if _, err := pf.file.Write(p.Data()); err != nil {
		return errors.ErrFileOperation
	}

	return nil
}

func (pf *PageFile) ArrayInfo() *array.Info {
	return pf.arrayInfo
}

func (pf *PageFile) calculatePageOffset(pageNumber int) int64 {
	headerSize := int64(SignatureSize) + int64((&Header{}).Size_())
	pageSize := int64(config.TotalPageSize(pf.arrayInfo.ElementSize))
	return headerSize + int64(pageNumber)*pageSize
}

// Package virtualmemory provides virtual memory array management with paging and caching.
package virtualmemory

import (
	"VirtualMemoryManagement/cache"
	"VirtualMemoryManagement/config"
	"VirtualMemoryManagement/errors"
	"VirtualMemoryManagement/storage"
	"VirtualMemoryManagement/types/array"
	"VirtualMemoryManagement/types/page"
	"encoding/binary"
	"strconv"
	"time"
)

type VirtualArray struct {
	pageStorage  storage.PageStorage
	varcharStore storage.VarcharStorage
	arrayInfo    *array.Info
	pageCache    cache.Cache
	varcharIndex map[int]int64
	cacheSize    int
}

// Create creates a new virtual array with the specified parameters.
// Uses DefaultCacheSize from config for cache capacity.
func Create(filename string, size int, typ array.Type, stringLength int) (*VirtualArray, error) {
	return CreateWithCacheSize(filename, size, typ, stringLength, config.DefaultCacheSize)
}

// CreateWithCacheSize creates a new virtual array with a custom cache size.
func CreateWithCacheSize(filename string, size int, typ array.Type, stringLength int, cacheSize int) (*VirtualArray, error) {
	if size <= 0 {
		return nil, errors.ErrInvalidType
	}

	if cacheSize < config.MinCacheSize {
		cacheSize = config.MinCacheSize
	}
	if cacheSize > config.MaxCacheSize {
		cacheSize = config.MaxCacheSize
	}

	pageFile := storage.NewPageFile(filename)
	if err := pageFile.Create(size, typ, stringLength); err != nil {
		return nil, err
	}

	va := &VirtualArray{
		pageStorage:  pageFile,
		arrayInfo:    pageFile.ArrayInfo(),
		pageCache:    cache.NewLRU(cacheSize),
		varcharIndex: make(map[int]int64),
		cacheSize:    cacheSize,
	}

	if typ == array.TypeVarchar {
		varcharFile := storage.NewVarcharFile(filename + ".varchar")
		if err := varcharFile.Create(); err != nil {
			return nil, errors.NewErrorWithWrapped(errors.ErrCodeFileOperation, "failed to create varchar file", err)
		}
		va.varcharStore = varcharFile
	}

	if err := va.loadInitialPages(); err != nil {
		return nil, err
	}

	return va, nil
}

// Open opens an existing virtual array from a file.
// Uses DefaultCacheSize from config for cache capacity.
func Open(filename string) (*VirtualArray, error) {
	return OpenWithCacheSize(filename, config.DefaultCacheSize)
}

// OpenWithCacheSize opens an existing virtual array with a custom cache size.
func OpenWithCacheSize(filename string, cacheSize int) (*VirtualArray, error) {
	if cacheSize < config.MinCacheSize {
		cacheSize = config.MinCacheSize
	}
	if cacheSize > config.MaxCacheSize {
		cacheSize = config.MaxCacheSize
	}

	pageFile := storage.NewPageFile(filename)
	if err := pageFile.Open(filename); err != nil {
		return nil, err
	}

	va := &VirtualArray{
		pageStorage:  pageFile,
		arrayInfo:    pageFile.ArrayInfo(),
		pageCache:    cache.NewLRU(cacheSize),
		varcharIndex: make(map[int]int64),
		cacheSize:    cacheSize,
	}

	if va.arrayInfo.Type == array.TypeVarchar {
		varcharFile := storage.NewVarcharFile(filename + ".varchar")
		if err := varcharFile.Open(); err != nil {
			return nil, errors.NewErrorWithWrapped(errors.ErrCodeFileOperation, "failed to open varchar file", err)
		}
		va.varcharStore = varcharFile

		if err := va.loadVarcharIndex(); err != nil {
			return nil, err
		}
	}

	if err := va.loadInitialPages(); err != nil {
		return nil, err
	}

	return va, nil
}

// Close closes the virtual array and flushes all dirty pages.
func (va *VirtualArray) Close() error {
	if err := va.pageStorage.Close(); err != nil {
		return err
	}
	if va.varcharStore != nil {
		if err := va.varcharStore.Close(); err != nil {
			return err
		}
	}
	return nil
}

func (va *VirtualArray) Read(index int) (interface{}, error) {
	if index < 0 || index >= va.arrayInfo.Size {
		return nil, errors.ErrIndexOutOfRange
	}

	p, offset, err := va.getPageAndOffset(index)
	if err != nil {
		return nil, err
	}

	switch va.arrayInfo.Type {
	case array.TypeInt:
		return va.readInt(p.Data(), offset), nil

	case array.TypeChar:
		return va.readChar(p.Data(), offset, va.arrayInfo.StringLength), nil

	case array.TypeVarchar:
		varcharOffset := int64(va.readInt(p.Data(), offset))
		if varcharOffset == 0 {
			return "", nil
		}
		if va.varcharStore == nil {
			return "", errors.ErrFileOperation
		}
		str, err := va.varcharStore.ReadString(varcharOffset)
		if err != nil {
			return "", nil
		}
		return str, nil

	default:
		return nil, errors.ErrInvalidType
	}
}

func (va *VirtualArray) Write(index int, value interface{}) error {
	if index < 0 || index >= va.arrayInfo.Size {
		return errors.ErrIndexOutOfRange
	}

	p, offset, err := va.getPageAndOffset(index)
	if err != nil {
		return err
	}

	switch va.arrayInfo.Type {
	case array.TypeInt:
		intVal, ok := value.(int32)
		if !ok {
			return errors.ErrInvalidType
		}
		va.writeInt(p.Data(), offset, intVal)

	case array.TypeChar:
		strVal, ok := value.(string)
		if !ok {
			return errors.ErrInvalidType
		}
		va.writeChar(p.Data(), offset, strVal, va.arrayInfo.StringLength)

	case array.TypeVarchar:
		strVal, ok := value.(string)
		if !ok {
			return errors.ErrInvalidType
		}

		varcharOffset, err := va.varcharStore.GetCurrentOffset()
		if err != nil {
			return err
		}

		if err := va.varcharStore.WriteString(varcharOffset, strVal); err != nil {
			return err
		}

		va.writeInt(p.Data(), offset, int32(varcharOffset))
		va.varcharIndex[index] = varcharOffset

	default:
		return errors.ErrInvalidType
	}

	bitIndex := index % config.BitsPerPage

	if err := p.SetBit(bitIndex); err != nil {
		return err
	}
	p.MakeDirty()

	return nil
}

func (va *VirtualArray) ArrayInfo() *array.Info {
	return va.arrayInfo
}

func (va *VirtualArray) getPageAndOffset(index int) (*page.Page, int, error) {
	pageNumber := index / config.BitsPerPage
	offsetInPage := (index % config.BitsPerPage) * va.arrayInfo.ElementSize

	p, err := va.ensurePageInCache(pageNumber)
	if err != nil {
		return nil, 0, err
	}

	return p, offsetInPage, nil
}

func (va *VirtualArray) ensurePageInCache(pageNumber int) (*page.Page, error) {
	if p := va.pageCache.Get(pageNumber); p != nil {
		p.MarkAccessed()
		return p, nil
	}

	p, err := va.pageStorage.ReadPage(pageNumber)
	if err != nil {
		return nil, err
	}

	evicted := va.pageCache.Put(p)
	if evicted != nil && evicted.Dirty {
		if err := va.pageStorage.WritePage(evicted); err != nil {
			return nil, err
		}
	}

	p.MarkAccessed()
	return p, nil
}

func (va *VirtualArray) loadInitialPages() error {
	count := va.cacheSize
	if count > va.arrayInfo.PageCount {
		count = va.arrayInfo.PageCount
	}

	for i := 0; i < count; i++ {
		if p := va.pageCache.Get(i); p != nil {
			continue
		}

		p, err := va.pageStorage.ReadPage(i)
		if err != nil {
			if errors.Is(err, errors.ErrFileOperation) {
				p = page.New(i, va.arrayInfo.ElementSize)
			} else {
				return err
			}
		}

		va.pageCache.Put(p)
	}

	return nil
}

func (va *VirtualArray) loadVarcharIndex() error {
	for i := 0; i < va.arrayInfo.Size; i++ {
		if p := va.pageCache.Get(i / config.BitsPerPage); p != nil {
			offset := (i % config.BitsPerPage) * va.arrayInfo.ElementSize
			varcharOffset := int64(va.readInt(p.Data(), offset))
			if varcharOffset != 0 {
				va.varcharIndex[i] = varcharOffset
			}
		}
	}
	return nil
}

func (va *VirtualArray) readInt(data []byte, offset int) int32 {
	return int32(binary.LittleEndian.Uint32(data[offset : offset+4]))
}

func (va *VirtualArray) writeInt(data []byte, offset int, value int32) {
	binary.LittleEndian.PutUint32(data[offset:offset+4], uint32(value))
}

func (va *VirtualArray) readInt64(data []byte, offset int) int64 {
	return int64(binary.LittleEndian.Uint64(data[offset : offset+8]))
}

func (va *VirtualArray) writeInt64(data []byte, offset int, value int64) {
	binary.LittleEndian.PutUint64(data[offset:offset+8], uint64(value))
}

func (va *VirtualArray) readChar(data []byte, offset int, length int) string {
	endIndex := offset + length
	if endIndex > len(data) {
		endIndex = len(data)
	}

	str := string(data[offset:endIndex])
	if idx := -1; true {
		for i, b := range data[offset:endIndex] {
			if b == 0 {
				idx = i
				break
			}
		}
		if idx != -1 {
			str = string(data[offset : offset+idx])
		}
	}
	return str
}

func (va *VirtualArray) writeChar(data []byte, offset int, value string, length int) {
	for i := 0; i < length && i < len(value); i++ {
		data[offset+i] = value[i]
	}
	for i := len(value); i < length; i++ {
		data[offset+i] = 0
	}
}

// FlushDirtyPages writes all dirty pages back to storage.
func (va *VirtualArray) FlushDirtyPages() error {
	pages := va.pageCache.All()
	for _, p := range pages {
		if p.Dirty {
			if err := va.pageStorage.WritePage(p); err != nil {
				return err
			}
			p.Dirty = false
		}
	}
	return nil
}

func (va *VirtualArray) GetStats() string {
	pages := va.pageCache.All()
	stats := "Virtual Array Stats:\n"
	stats += "Array Type: " + va.arrayInfo.Type.String() + "\n"
	stats += "Array Size: " + strconv.Itoa(va.arrayInfo.Size) + "\n"
	stats += "Element Size: " + strconv.Itoa(va.arrayInfo.ElementSize) + " bytes\n"
	stats += "Total Pages: " + strconv.Itoa(va.arrayInfo.PageCount) + "\n"
	stats += "Cached Pages: " + strconv.Itoa(len(pages)) + "\n"
	stats += "Page Details:\n"

	for _, p := range pages {
		stats += "  Page " + strconv.Itoa(p.AbsoluteNumber) +
			" | Dirty: " + strconv.FormatBool(p.Dirty) +
			" | Accesses: " + strconv.Itoa(p.AccessCounter) +
			" | Last Access: " + p.AccessTime.Format(time.RFC3339Nano) + "\n"
	}

	return stats
}

